import{_ as t,o as s,c as a,g as e}from"./chunks/framework.CtuiYkcd.js";const x=JSON.parse('{"title":"霍金之死","description":"","frontmatter":{"title":"霍金之死","date":"2018-03-14T07:34:00.016Z","length":"714字","time":"3分钟","aside":false,"hash":-1904848963},"headers":[],"relativePath":"article/霍金之死.md","filePath":"article/霍金之死.md"}'),o={name:"article/霍金之死.md"},n=e("p",null,"今天，霍金死了。我却很想像 Camus 一样在后面加上一句“也许是昨天”。这样这个句子似乎就成了一句自言自语。这句话本身似乎有某种魅力，诱惑我揣摩它。",-1),_=e("p",null,"然而我并未画蛇添足，可单就这六个字，也够人们玩味的了。经学家说孔子述《春秋》，其文之简，只叙事，不发论抒情，其志却一览无遗。我不敢妄议孔夫子的动机与其中寓意，却对文字的深意与它能携带的情感大为惊惑。我真的无法做到不带任何感情色彩的说出这句话吗？",-1),l=e("p",null,"我是刻意的，因为如果一种感觉不够深刻就无法将其化为语言。我所知道的，是霍金死了。我对他的了解不如牛顿、爱因斯坦、玻尔，与他的共情不如王勃、史铁生、Dolores，甚至不如只有萍水之缘的余光中。因而我咂摸不出任何情感，为他之死这句话配上任何情感，亦或我想借这六个字表达什么“奠念哀悼”的心情，都非我本意。可我发现，单纯叙述此事是多么困难，不如沉默以表达我的无感。",-1),c=e("p",null,"我的困难实则源于人们对习惯情境作出反应的传统。婚礼喜、丧礼哀，对关系至密的亲友产生这样的感情不足为奇。但 Camus 笔下的默尔索也无动于衷，他想告诉我们即便无动于衷也不足为奇。对至亲至爱的人尚且如此，更何况与我素昧平生的另一个人呢？哪怕是再伟大的人，若只活在别人口中，那也只能活在我耳中罢了，带给我的感受恐怕不如我的一粒耳屎真切。且先莫笑或指摘我的冷漠。感情是无辜的，可我们习惯于将它归因于态度与道德，以至于未对母亲之死表示悲恸的默尔索沦于“道德败坏”的罪名——我们无法对感情负责，它是脑中的一团混沌。我们表达出的感情，是理智加工的产物，它合理却并不一定合情。我想，责任的适用范围也就到理智为止吧。",-1),r=e("p",null,"所谓合理，是一种约定。它使人们表达的情感不至于如同它的源头一样难以捉摸，以致在外人看来觉得“乖戾无常”或“不近人情”。为了社会交流的方便，人们以惯例表达情感——这种情感是社会化的，而非“内心的感受”。因此，发布在网上的那些悼念霍金的动态，就其反映内心的感受而言，几乎不比我深刻多少。",-1),i=[n,_,l,c,r];function d(p,h,m,u,f,$){return s(),a("div",null,i)}const B=t(o,[["render",d]]);export{x as __pageData,B as default};
